module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output reg mul_out
);
parameter M = 8, N = 8;
reg [7:0] mul_a_reg, mul_b_reg;
reg mul_en_out_reg;
reg [15:0] partial_prod[N-1:0], temp[N-1:0];
reg [15:0] sum[N-1:0];
reg [16:0] final_sum;
// Input Control
always @(posedge clk) begin
    if (!rst_n) begin
        mul_en_out_reg <= 0;
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
    else begin
        mul_en_out_reg <= {mul_en_out_reg[N-2:0], mul_en_in};
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end
assign mul_en_out = mul_en_out_reg[N-1];
// Input Registers
always @(posedge clk) begin
    if (!rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
    else begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end
// Partial Product Generation
genvar i;
generate
    for (i = 0; i < N; i = i + 1) begin : gen_partial_products
        assign temp[i] = {8'b0, mul_b_reg[i]} & mul_a_reg;
    end
endgenerate
// Partial Sum Calculation
always @(posedge clk) begin
    if (!rst_n) begin
        for (int i = 0; i < N; i = i + 1)
            sum[i] <= 0;
        final_sum <= 0;
    end
    else begin
        for (int i = 0; i < N; i = i + 1)
            sum[i] <= (i == 0) ? temp[i] : sum[i-1] + temp[i];
        final_sum <= sum[N-1];
    end
end
// Final Product Calculation
always @(posedge clk) begin
    if (!rst_n)
        mul_out <= 0;
    else
        mul_out <= mul_en_out_reg ? final_sum : 0;
end
endmodule
